@* ───── Component State & Logic ───── *@
@code {
    // Navigation
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;
    private bool _saving;

    private record SectionDef(string Key, string Label, string Icon);
    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;

    // Profile
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // Notifications
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "random", "social"];

    // Security
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private List<ActiveSession> _sessions = [];
    private string _currentSessionId = "";
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private string _appearanceTheme = "System";
    private string _appearanceFontSize = "Medium";
    private string _appearanceLanguage = "en";
    private bool _appearanceCompact;

    // Lifecycle
    protected override async Task OnInitializedAsync()
    {
        try
        {
            var profileTask = SettingsService.GetProfileAsync();
            var notifTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

            LoadProfile(await profileTask);
            LoadNotifications(await notifTask);
            LoadSecurity(await securityTask);
            LoadAppearance(await appearanceTask);
        }
        catch
        {
            ShowToast("Failed to load settings.", isError: true);
        }
        finally
        {
            _loading = false;
        }
    }

    // ── Profile ──

    private void LoadProfile(UserProfile profile)
    {
        _savedProfile = profile;
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            ShowToast("Profile saved successfully.");
        }
        catch
        {
            ShowToast("Failed to save profile.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            LoadProfile(_savedProfile);
        }
    }

    // ── Notifications ──

    private void LoadNotifications(NotificationPrefs prefs)
    {
        _notifEmail = prefs.EmailNotifications;
        _notifPush = prefs.PushNotifications;
        _notifWeeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
    }

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifWeeklyDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowToast("Notification preferences saved.");
        }
        catch
        {
            ShowToast("Failed to save preferences.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Security ──

    private void LoadSecurity(SecuritySettings settings)
    {
        _security = settings;
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _sessions = settings.Sessions.ToList();
        _currentSessionId = settings.Sessions.FirstOrDefault()?.Id ?? "";
    }

    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            ShowToast("Password updated successfully.");
        }
        catch
        {
            _passwordError = "Failed to change password. Please verify your current password.";
        }
        finally
        {
            _saving = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;

        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
            _sessionToRevoke = null;
        }
        catch
        {
            ShowToast("Failed to revoke session.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Appearance ──

    private void LoadAppearance(AppearanceSettings settings)
    {
        _appearanceTheme = settings.Theme;
        _appearanceFontSize = settings.FontSize;
        _appearanceLanguage = settings.Language;
        _appearanceCompact = settings.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_appearanceTheme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "light" => "preview-light",
            _ => "preview-system"
        });
        classes.Add(_appearanceFontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_appearanceCompact) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_appearanceTheme, _appearanceFontSize, _appearanceLanguage, _appearanceCompact);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowToast("Appearance settings saved.");
        }
        catch
        {
            ShowToast("Failed to save appearance settings.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Helpers ──

    private async void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        await Task.Delay(3000);
        _toastVisible = false;
        StateHasChanged();
    }

    private static string TruncateUrl(string? url, int maxLen)
    {
        if (string.IsNullOrWhiteSpace(url)) return "—";
        return url.Length <= maxLen ? url : string.Concat(url.AsSpan(0, maxLen - 1), "…");
    }
}

