namespace sv_e2ea424a7bd747518553f903b1f0cac4.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@page "/settings"
@rendermode InteractiveServer
@using sv_e2ea424a7bd747518553f903b1f0cac4.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }
    </div>
</div>

@* ───── Profile Section ───── *@
@code {
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Profile</h3>
            <p class="text-muted">Manage your public profile information.</p>

            <div class="settings-card">
                <div class="profile-top">
                    <div class="avatar-area">
                        @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                        {
                            <img src="@_profileAvatarUrl" alt="Avatar" class="avatar-preview" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">No Avatar</div>
                        }
                        <small class="text-muted mt-1 avatar-url-label" title="@_profileAvatarUrl">@TruncateUrl(_profileAvatarUrl, 36)</small>
                    </div>

                    <div class="profile-fields">
                        <div class="mb-3">
                            <label class="form-label">Display Name</label>
                            <input type="text" class="form-control" @bind="_profileDisplayName" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Email</label>
                            <input type="email" class="form-control" @bind="_profileEmail" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Bio</label>
                            <textarea class="form-control" rows="3" @bind="_profileBio"></textarea>
                        </div>
                    </div>
                </div>

                <div class="button-row">
                    <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save Changes
                    </button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@_saving">Discard Changes</button>
                </div>
            </div>
        </section>
    };
}

@* ───── Notifications Section ───── *@
@code {
    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Notifications</h3>
            <p class="text-muted">Choose how you want to be notified.</p>

            <div class="settings-card">
                <div class="toggle-row">
                    <div>
                        <strong>Email Notifications</strong>
                        <div class="text-muted small">Receive notifications via email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_notifEmail" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Push Notifications</strong>
                        <div class="text-muted small">Receive push notifications in your browser</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_notifPush" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Weekly Digest</strong>
                        <div class="text-muted small">Get a weekly summary of activity</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_notifWeeklyDigest" />
                    </div>
                </div>
            </div>

            <div class="settings-card mt-3">
                <h6>Muted Channels</h6>
                <p class="text-muted small">Uncheck a channel to unmute it.</p>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted small fst-italic">No channels available.</p>
                }
                else
                {
                    <div class="channel-list">
                        @foreach (var channel in _allChannels)
                        {
                            var isMuted = _mutedChannels.Contains(channel);
                            <div class="form-check">
                                <input class="form-check-input darker-border-checkbox" type="checkbox" id="@($"ch-{channel}")"
                                       checked="@isMuted"
                                       @onchange="e => ToggleMuteChannel(channel, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="button-row mt-3">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </section>
    };
}

@* ───── Security Section ───── *@
@code {
    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h3>Security</h3>
            <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>

            @* Change Password *@
            <div class="settings-card">
                <div class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <h6 class="mb-0">Change Password</h6>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <div class="alert alert-danger py-2">@_passwordError</div>
                        }
                        <button class="btn btn-primary" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="settings-card mt-3">
                <div class="toggle-row">
                    <div>
                        <strong>Two-Factor Authentication</strong>
                        <div class="text-muted small">
                            Status:
                            @if (_twoFactorEnabled)
                            {
                                <span class="badge bg-success">Enabled</span>
                            }
                            else
                            {
                                <span class="badge bg-secondary">Disabled</span>
                            }
                        </div>
                        @if (_security?.LastPasswordChange is not null)
                        {
                            <div class="text-muted small mt-1">Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")</div>
                        }
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
                    </div>
                </div>
            </div>

            @* Active Sessions *@
            <div class="settings-card mt-3">
                <h6>Active Sessions</h6>
                @if (_sessions.Count == 0)
                {
                    <p class="text-muted small fst-italic">No active sessions.</p>
                }
                else
                {
                    <div class="table-responsive">
                        <table class="table table-sm align-middle mb-0">
                            <thead>
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th></th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var session in _sessions)
                                {
                                    var isCurrent = session.Id == _currentSessionId;
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isCurrent)
                                            {
                                                <span class="badge bg-info ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                                        <td class="text-end">
                                            @if (!isCurrent)
                                            {
                                                <button class="btn btn-sm btn-outline-danger"
                                                        @onclick="() => PromptRevokeSession(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                }
            </div>

            @* Revoke confirmation dialog *@
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop-custom" @onclick="() => _sessionToRevoke = null"></div>
                <div class="confirm-dialog">
                    <h6>Revoke Session</h6>
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                    <div class="d-flex gap-2 justify-content-end">
                        <button class="btn btn-sm btn-outline-secondary" @onclick="() => _sessionToRevoke = null">Cancel</button>
                        <button class="btn btn-sm btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Revoke
                        </button>
                    </div>
                </div>
            }
        </section>
    };
}

@* ───── Appearance Section ───── *@
@code {
    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Appearance</h3>
            <p class="text-muted">Customize the look and feel of the application.</p>

            <div class="settings-card">
                <div class="mb-4">
                    <h6>Theme</h6>
                    <div class="d-flex gap-3">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                                       value="@theme"
                                       checked="@(_appearanceTheme == theme)"
                                       @onchange="() => _appearanceTheme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    <div class="d-flex gap-3">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                                       value="@size"
                                       checked="@(_appearanceFontSize == size)"
                                       @onchange="() => _appearanceFontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 250px;" @bind="_appearanceLanguage">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                <div class="mb-4">
                    <div class="toggle-row">
                        <div>
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch" @bind="_appearanceCompact" />
                        </div>
                    </div>
                </div>
            </div>

            @* Live Preview *@
            <div class="settings-card mt-3">
                <h6>Preview</h6>
                <div class="appearance-preview @GetPreviewClasses()">
                    <div class="preview-header">Sample Header</div>
                    <p class="preview-body">This is a preview of your selected appearance settings. The theme, font size, and compact mode are reflected here.</p>
                    <div class="d-flex gap-2">
                        <button class="btn btn-sm btn-primary">Primary</button>
                        <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                    </div>
                </div>
            </div>

            <div class="button-row mt-3">
                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save
                </button>
            </div>
        </section>
    };
}

@* ───── Component State & Logic ───── *@
@code {
    // Navigation
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;
    private bool _saving;

    private record SectionDef(string Key, string Label, string Icon);
    private static readonly SectionDef[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;

    // Profile
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // Notifications
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "random", "social"];

    // Security
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private List<ActiveSession> _sessions = [];
    private string _currentSessionId = "";
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;

    // Appearance
    private string _appearanceTheme = "System";
    private string _appearanceFontSize = "Medium";
    private string _appearanceLanguage = "en";
    private bool _appearanceCompact;

    // Lifecycle
    protected override async Task OnInitializedAsync()
    {
        try
        {
            var profileTask = SettingsService.GetProfileAsync();
            var notifTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

            LoadProfile(await profileTask);
            LoadNotifications(await notifTask);
            LoadSecurity(await securityTask);
            LoadAppearance(await appearanceTask);
        }
        catch
        {
            ShowToast("Failed to load settings.", isError: true);
        }
        finally
        {
            _loading = false;
        }
    }

    // ── Profile ──

    private void LoadProfile(UserProfile profile)
    {
        _savedProfile = profile;
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            ShowToast("Profile saved successfully.");
        }
        catch
        {
            ShowToast("Failed to save profile.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            LoadProfile(_savedProfile);
        }
    }

    // ── Notifications ──

    private void LoadNotifications(NotificationPrefs prefs)
    {
        _notifEmail = prefs.EmailNotifications;
        _notifPush = prefs.PushNotifications;
        _notifWeeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
    }

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifWeeklyDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowToast("Notification preferences saved.");
        }
        catch
        {
            ShowToast("Failed to save preferences.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Security ──

    private void LoadSecurity(SecuritySettings settings)
    {
        _security = settings;
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _sessions = settings.Sessions.ToList();
        _currentSessionId = settings.Sessions.FirstOrDefault()?.Id ?? "";
    }

    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            ShowToast("Password updated successfully.");
        }
        catch
        {
            _passwordError = "Failed to change password. Please verify your current password.";
        }
        finally
        {
            _saving = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;

        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
            _sessionToRevoke = null;
        }
        catch
        {
            ShowToast("Failed to revoke session.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Appearance ──

    private void LoadAppearance(AppearanceSettings settings)
    {
        _appearanceTheme = settings.Theme;
        _appearanceFontSize = settings.FontSize;
        _appearanceLanguage = settings.Language;
        _appearanceCompact = settings.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_appearanceTheme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "light" => "preview-light",
            _ => "preview-system"
        });
        classes.Add(_appearanceFontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_appearanceCompact) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_appearanceTheme, _appearanceFontSize, _appearanceLanguage, _appearanceCompact);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowToast("Appearance settings saved.");
        }
        catch
        {
            ShowToast("Failed to save appearance settings.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Helpers ──

    private async void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        await Task.Delay(3000);
        _toastVisible = false;
        StateHasChanged();
    }

    private static string TruncateUrl(string? url, int maxLen)
    {
        if (string.IsNullOrWhiteSpace(url)) return "—";
        return url.Length <= maxLen ? url : string.Concat(url.AsSpan(0, maxLen - 1), "…");
    }
}

/* ── Layout ── */
.settings-layout {
    display: flex;
    min-height: calc(100vh - 3.5rem);
    gap: 0;
}

.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-size: 0.95rem;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.settings-nav-item:hover {
    background: #e9ecef;
}

.settings-nav-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

.nav-icon {
    font-size: 1.1rem;
    width: 1.4rem;
    text-align: center;
}

.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    position: relative;
    max-width: 800px;
}

/* ── Section & Card ── */
.settings-section h3 {
    font-size: 1.4rem;
    font-weight: 600;
    margin-bottom: 0.2rem;
}

.settings-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-top: 1rem;
}

/* ── Profile ── */
.profile-top {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex-shrink: 0;
}

.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

.avatar-placeholder {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.8rem;
    border: 2px dashed #adb5bd;
}

.avatar-url-label {
    max-width: 120px;
    text-align: center;
    word-break: break-all;
}

.profile-fields {
    flex: 1;
}

/* ── Toggle rows ── */
.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 0;
}

.toggle-row + .toggle-row {
    border-top: 1px solid #f0f0f0;
}

/* ── Channel list ── */
.channel-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
    gap: 0.4rem;
}

/* ── Expandable panel ── */
.expandable-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    user-select: none;
}

.expand-icon {
    font-size: 0.75rem;
    color: #6c757d;
}

.expandable-body {
    margin-top: 1rem;
    padding-top: 1rem;
    border-top: 1px solid #f0f0f0;
}

/* ── Confirmation dialog ── */
.modal-backdrop-custom {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.35);
    z-index: 1040;
}

.confirm-dialog {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    background: #fff;
    border-radius: 0.5rem;
    padding: 1.5rem;
    z-index: 1050;
    width: 420px;
    max-width: 90vw;
    box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.2);
}

/* ── Button rows ── */
.button-row {
    display: flex;
    gap: 0.5rem;
    margin-top: 1rem;
}

/* ── Toast ── */
.settings-toast {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    padding: 0.75rem 1.25rem;
    border-radius: 0.4rem;
    color: #fff;
    font-size: 0.9rem;
    z-index: 1100;
    animation: toast-in 0.3s ease;
    box-shadow: 0 0.25rem 0.75rem rgba(0,0,0,0.15);
}

.toast-success {
    background: #198754;
}

.toast-error {
    background: #dc3545;
}

@keyframes toast-in {
    from { opacity: 0; transform: translateY(1rem); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Appearance Preview ── */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.4rem;
    padding: 1.25rem;
    transition: all 0.2s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .btn-outline-secondary {
    color: #cdd6f4;
    border-color: #585b70;
}

.preview-system {
    background: #f8f9fa;
    color: #212529;
}

.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 0.95rem;
}

.preview-font-lg {
    font-size: 1.15rem;
}

.preview-compact {
    padding: 0.6rem;
    line-height: 1.3;
}

.preview-header {
    font-weight: 700;
    margin-bottom: 0.5rem;
    font-size: 1.1em;
}

.preview-body {
    margin-bottom: 0.75rem;
}

