{"path": "/tmp/sv-e2ea424a7bd747518553f903b1f0cac4/Components/Pages/Settings.razor", "file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_e2ea424a7bd747518553f903b1f0cac4.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="settings-nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                @_toastMessage
            </div>
        }
    </div>
</div>

@* ───── Profile Section ───── *@
@code {
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Profile</h3>
            <p class="text-muted">Manage your public profile information.</p>

            <div class="settings-card">
                <div class="profile-top">
                    <div class="avatar-area">
                        @if (!string.IsNullOrWhiteSpace(_profileAvatarUrl))
                        {
                            <img src="@_profileAvatarUrl" alt="Avatar" class="avatar-preview" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">No Avatar</div>
                        }
                        <small class="text-muted mt-1 avatar-url-label" title="@_profileAvatarUrl">@TruncateUrl(_profileAvatarUrl, 36)</small>
                    </div>

                    <div class="profile-fields">
                        <div class="mb-3">
                            <label class="form-label">Display Name</label>
                            <input type="text" class="form-control" @bind="_profileDisplayName" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Email</label>
                            <input type="email" class="form-control" @bind="_profileEmail" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Bio</label>
                            <textarea class="form-control" rows="3" @bind="_profileBio"></textarea>
                        </div>
                    </div>
                </div>

                <div class="button-row">
                    <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save Changes
                    </button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@_saving">Discard Changes</button>
                </div>
            </div>
        </section>
    };
}

@* ───── Notifications Section ───── *@
@code {
    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Notifications</h3>
            <p class="text-muted">Choose how you want to be notified.</p>

            <div class="settings-card">
                <div class="toggle-row">
                    <div>
                        <strong>Email Notifications</strong>
                        <div class="text-muted small">Receive notifications via email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_notifEmail" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Push Notifications</strong>
                        <div class="text-muted small">Receive push notifications in your browser</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_notifPush" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Weekly Digest</strong>
                        <div class="text-muted small">Get a weekly summary of activity</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" @bind="_notifWeeklyDigest" />
                    </div>
                </div>
            </div>

            <div class="settings-card mt-3">
                <h6>Muted Channels</h6>
                <p class="text-muted small">Uncheck a channel to unmute it.</p>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted small fst-italic">No channels available.</p>
                }
                else
                {
                    <div class="channel-list">
                        @foreach (var channel in _allChannels)
                        {
                            var isMuted = _mutedChannels.Contains(channel);
                            <div class="form-check">
                                <input class="form-check-input darker-border-checkbox" type="checkbox" id="@($"ch-{channel}")"
                                       checked="@isMuted"
                                       @onchange="e => ToggleMuteChannel(channel, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="button-row mt-3">
                <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Preferences
                </button>
            </div>
        </section>
    };
}

