                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                }
            </div>

            @* Revoke confirmation dialog *@
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop-custom" @onclick="() => _sessionToRevoke = null"></div>
