                    <div class="d-flex gap-2 justify-content-end">
                        <button class="btn btn-sm btn-outline-secondary" @onclick="() => _sessionToRevoke = null">Cancel</button>
                        <button class="btn btn-sm btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Revoke
                        </button>
                    </div>
                </div>
            }
        </section>
    };
}

