+    display: flex;
+    align-items: center;
+    gap: 0.6rem;
+    padding: 0.6rem 1.25rem;
+    cursor: pointer;
+    color: #495057;
+    font-size: 0.95rem;
+    transition: background-color 0.15s, color 0.15s;
+    border-left: 3px solid transparent;
+}
+
+.settings-nav-item:hover {
+    background: #e9ecef;
+}
+
+.settings-nav-item.active {
+    background: #e7f1ff;
+    color: #0d6efd;
+    font-weight: 600;
+    border-left-color: #0d6efd;
+}
+
+.nav-icon {
+    font-size: 1.1rem;
+    width: 1.4rem;
+    text-align: center;
+}
+
+.settings-content {
+    flex: 1;
+    padding: 1.5rem 2rem;
+    position: relative;
+    max-width: 800px;
+}
+
+/* ── Section & Card ── */
+.settings-section h3 {
+    font-size: 1.4rem;
+    font-weight: 600;
+    margin-bottom: 0.2rem;
+}
+
+.settings-card {
+    background: #fff;
+    border: 1px solid #dee2e6;
+    border-radius: 0.5rem;
+    padding: 1.25rem;
+    margin-top: 1rem;
+}
+
+/* ── Profile ── */
+.profile-top {
+    display: flex;
+    gap: 2rem;
+}
+
+.avatar-area {
+    display: flex;
+    flex-direction: column;
+    align-items: center;
+    flex-shrink: 0;
+}
+
+.avatar-preview {
+    width: 96px;
+    height: 96px;
+    border-radius: 50%;
+    object-fit: cover;
+    border: 2px solid #dee2e6;
+}
+
+.avatar-placeholder {
+    width: 96px;
+    height: 96px;
+    border-radius: 50%;
+    background: #e9ecef;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    color: #6c757d;
+    font-size: 0.8rem;
+    border: 2px dashed #adb5bd;
+}
+
+.avatar-url-label {
+    max-width: 120px;
+    text-align: center;
+    word-break: break-all;
+}
+
+.profile-fields {
+    flex: 1;
+}
+
+/* ── Toggle rows ── */
+.toggle-row {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 0.75rem 0;
+}
+
+.toggle-row + .toggle-row {
+    border-top: 1px solid #f0f0f0;
+}
+
+/* ── Channel list ── */
+.channel-list {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
+    gap: 0.4rem;
+}
+
+/* ── Expandable panel ── */
+.expandable-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    cursor: pointer;
+    user-select: none;
+}
+
+.expand-icon {
+    font-size: 0.75rem;
+    color: #6c757d;
+}
+
+.expandable-body {
+    margin-top: 1rem;
+    padding-top: 1rem;
+    border-top: 1px solid #f0f0f0;
+}
+
+/* ── Confirmation dialog ── */
+.modal-backdrop-custom {
+    position: fixed;
+    inset: 0;
+    background: rgba(0,0,0,0.35);
+    z-index: 1040;
+}
+
+.confirm-dialog {
+    position: fixed;
+    top: 50%;
+    left: 50%;
+    transform: translate(-50%, -50%);
+    background: #fff;
+    border-radius: 0.5rem;
+    padding: 1.5rem;
+    z-index: 1050;
+    width: 420px;
+    max-width: 90vw;
+    box-shadow: 0 0.5rem 1.5rem rgba(0,0,0,0.2);
+}
+
+/* ── Button rows ── */
+.button-row {
+    display: flex;
+    gap: 0.5rem;
+    margin-top: 1rem;
+}
+
+/* ── Toast ── */
+.settings-toast {
+    position: fixed;
+    bottom: 1.5rem;
+    right: 1.5rem;
+    padding: 0.75rem 1.25rem;
+    border-radius: 0.4rem;
+    color: #fff;
+    font-size: 0.9rem;
+    z-index: 1100;
+    animation: toast-in 0.3s ease;
+    box-shadow: 0 0.25rem 0.75rem rgba(0,0,0,0.15);
+}
+
+.toast-success {
+    background: #198754;
+}
+
+.toast-error {
+    background: #dc3545;
+}
+
+@keyframes toast-in {
+    from { opacity: 0; transform: translateY(1rem); }
+    to   { opacity: 1; transform: translateY(0); }
+}
+
+/* ── Appearance Preview ── */
+.appearance-preview {
+    border: 1px solid #dee2e6;
+    border-radius: 0.4rem;
+    padding: 1.25rem;
+    transition: all 0.2s ease;
+}
+
+.preview-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+    border-color: #45475a;
+}
+
+.preview-dark .btn-outline-secondary {
+    color: #cdd6f4;
+    border-color: #585b70;
+}
+
+.preview-system {
+    background: #f8f9fa;
+    color: #212529;
+}
+
+.preview-font-sm {
+    font-size: 0.8rem;
+}
+
+.preview-font-md {
+    font-size: 0.95rem;
+}
+
+.preview-font-lg {
+    font-size: 1.15rem;
+}
+
+.preview-compact {
+    padding: 0.6rem;
+    line-height: 1.3;
+}
+
+.preview-header {
+    font-weight: 700;
+    margin-bottom: 0.5rem;
+    font-size: 1.1em;
+}
+
+.preview-body {
+    margin-bottom: 0.75rem;
+}
+
